mapper.select:
SELECT * FROM users
WHERE username = #{username}
  AND id != #{excludeId}
LIMIT 1

SELECT u.id, u.username, u.display_name, u.avatar_url, u.bio,
       u.follower_count, u.following_count, u.created_at,
       EXISTS(
           SELECT 1 FROM user_follows uf
           WHERE uf.follower_id  = #{currentUserId}
             AND uf.following_id = #{targetId}
       ) AS followed_by_current_user
FROM users u
WHERE u.id = #{targetId}
